(function (global) {
  "use strict";

  function parseToken(token) {
    let raw = token.trim();
    const unique = raw.startsWith("&");
    if (unique) raw = raw.slice(1);
    const auto = raw.startsWith("++");
    if (auto) raw = raw.slice(2);
    if (raw.startsWith("[") && raw.endsWith("]")) {
      return { keyPath: raw.slice(1, -1).split("+"), unique, auto };
    }
    return { keyPath: raw, unique, auto };
  }

  function indexName(keyPath) {
    return Array.isArray(keyPath) ? keyPath.join("+") : keyPath;
  }

  class DexieTable {
    constructor(db, name) {
      this.db = db;
      this.name = name;
    }

    async _store(mode) {
      const database = await this.db._open();
      return database.transaction(this.name, mode).objectStore(this.name);
    }

    async clear() {
      const database = await this.db._open();
      return new Promise((resolve, reject) => {
        const tx = database.transaction(this.name, "readwrite");
        tx.objectStore(this.name).clear();
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
      });
    }

    async delete(key) {
      const store = await this._store("readwrite");
      return new Promise((resolve, reject) => {
        const request = store.delete(key);
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error);
      });
    }

    async get(key) {
      const store = await this._store("readonly");
      return new Promise((resolve, reject) => {
        const request = store.get(key);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
      });
    }

    async put(value) {
      const store = await this._store("readwrite");
      return new Promise((resolve, reject) => {
        const request = store.put(value);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
      });
    }

    async bulkPut(values) {
      const database = await this.db._open();
      return new Promise((resolve, reject) => {
        const tx = database.transaction(this.name, "readwrite");
        const store = tx.objectStore(this.name);
        for (const value of values || []) store.put(value);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
      });
    }

    async toArray() {
      const store = await this._store("readonly");
      return new Promise((resolve, reject) => {
        const request = store.getAll();
        request.onsuccess = () => resolve(request.result || []);
        request.onerror = () => reject(request.error);
      });
    }
  }

  class Dexie {
    constructor(name) {
      this.name = name;
      this._schema = {};
      this._version = 1;
      this._promise = null;
    }

    version(versionNumber) {
      this._version = versionNumber;
      return {
        stores: (schema) => {
          this._schema = schema || {};
          for (const tableName of Object.keys(this._schema)) {
            this[tableName] = this.table(tableName);
          }
          return this;
        },
      };
    }

    table(name) {
      return new DexieTable(this, name);
    }

    async open() {
      return this._open();
    }

    _open() {
      if (this._promise) return this._promise;
      this._promise = new Promise((resolve, reject) => {
        const request = global.indexedDB.open(this.name, this._version);
        request.onupgradeneeded = () => {
          const database = request.result;
          for (const [tableName, spec] of Object.entries(this._schema)) {
            if (database.objectStoreNames.contains(tableName)) continue;
            const tokens = String(spec).split(",").map((token) => token.trim()).filter(Boolean);
            const primary = parseToken(tokens[0] || "id");
            const store = database.createObjectStore(tableName, {
              keyPath: primary.keyPath,
              autoIncrement: primary.auto,
            });
            for (const token of tokens.slice(1)) {
              const parsed = parseToken(token);
              store.createIndex(indexName(parsed.keyPath), parsed.keyPath, {
                unique: parsed.unique,
              });
            }
          }
        };
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
      });
      return this._promise;
    }

    static delete(name) {
      return new Promise((resolve, reject) => {
        const request = global.indexedDB.deleteDatabase(name);
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error);
        request.onblocked = () => reject(new Error("Database delete is blocked by another tab."));
      });
    }
  }

  global.Dexie = Dexie;
})(window);
